svg.script:
(function () {
  var KEY = "generic";
  var SCALE = 0.6;
  var GATE_PINS = {"gate-Not":{"in1":[-60,0],"out":[80,0]},"gate-And":{"in1":[-62,-23],"in2":[-62,23],"out":[66,0]},"gate-Or":{"in1":[-58,-23],"in2":[-58,23],"out":[80,0]},"gate-AND3way":{"in1":[-62,-27],"in2":[-62,0],"in3":[-62,27],"out":[66,0]},"gate-OR4way":{"in1":[-60.326107,-30],"in2":[-59.462559,-9.9898129],"in3":[-59.919762,10.020376],"in4":[-60.369907,30],"out":[80,0]}};
  var CARD = {"inputInt1":[230,188],"inputInt2":[230,388],"inputInt3":[300,150],"outputInt":[770,288]};
  var TYPES = {"not-c":"gate-Not","not-in1":"gate-Not","not-in2":"gate-Not","and-m1":"gate-AND3way","and-m2":"gate-AND3way","and-m3":"gate-AND3way","and-m4":"gate-AND3way","or-final":"gate-OR4way"};
  var CONN = [["task-card-1.inputInt2","not-in2.in1"],["task-card-1.inputInt1","not-in1.in1"],["task-card-1.inputInt3","not-c.in1"],["task-card-1.inputInt1","and-m1.in1"],["not-in2.out","and-m1.in2"],["not-c.out","and-m1.in3"],["task-card-1.inputInt1","and-m2.in1"],["task-card-1.inputInt2","and-m2.in2"],["not-c.out","and-m2.in3"],["not-in1.out","and-m3.in1"],["task-card-1.inputInt2","and-m3.in2"],["task-card-1.inputInt3","and-m3.in3"],["task-card-1.inputInt1","and-m4.in1"],["task-card-1.inputInt2","and-m4.in2"],["task-card-1.inputInt3","and-m4.in3"],["and-m1.out","or-final.in1"],["and-m2.out","or-final.in2"],["and-m3.out","or-final.in3"],["and-m4.out","or-final.in4"],["or-final.out","task-card-1.outputInt"]];
  var NS = "http://www.w3.org/2000/svg";
  function rootCTM() { var s = document.querySelector("svg"); try { return s.getScreenCTM(); } catch (e) { return null; } }
  function center(id) {
    var r = document.querySelector('[data-mux-comp][data-id="' + id + '"]');
    if (!r) return null;
    var bb; try { bb = r.getBBox(); } catch (e) { return null; }
    var cx = bb.x + bb.width / 2, cy = bb.y + bb.height / 2;
    var root = rootCTM(), m = null;
    try { if (root) m = root.inverse().multiply(r.getScreenCTM()); } catch (e) { m = null; }
    if (m) return [m.a * cx + m.c * cy + m.e, m.b * cx + m.d * cy + m.f];
    return [cx, cy];
  }
  function pin(ref) {
    var i = ref.indexOf("."), comp = ref.slice(0, i), p = ref.slice(i + 1);
    if (comp === "task-card-1") return CARD[p] ? CARD[p].slice() : null;
    var c = center(comp); if (!c) return null;
    var off = GATE_PINS[TYPES[comp]] && GATE_PINS[TYPES[comp]][p]; if (!off) return null;
    return [c[0] + off[0] * SCALE, c[1] + off[1] * SCALE];
  }
  function drawWires() {
    var g = document.getElementById("mux-wires"); if (!g) return;
    while (g.firstChild) g.removeChild(g.firstChild);
    for (var i = 0; i < CONN.length; i++) {
      var a = pin(CONN[i][0]), b = pin(CONN[i][1]); if (!a || !b) continue;
      var ln = document.createElementNS(NS, "line");
      ln.setAttribute("x1", a[0]); ln.setAttribute("y1", a[1]);
      ln.setAttribute("x2", b[0]); ln.setAttribute("y2", b[1]);
      ln.setAttribute("stroke", "#101010"); ln.setAttribute("stroke-width", "5"); ln.setAttribute("stroke-linecap", "round");
      g.appendChild(ln);
    }
  }
  function collect() {
    var out = [];
    for (var id in TYPES) { var c = center(id); if (c) out.push({ id: id, x: c[0], y: c[1] }); }
    return { key: KEY, components: out };
  }
  function send() { try { if (window.parent && window.parent !== window) window.parent.postMessage({ __muxSolutionLayout: true, payload: collect() }, "*"); } catch (e) {} }
  function tick() { drawWires(); send(); }
  function boot() { tick(); setTimeout(tick, 120); setTimeout(tick, 500); }
  if (document.readyState === "loading") window.addEventListener("DOMContentLoaded", boot); else boot();
  window.addEventListener("load", tick);
})();
